define("local_coursetags/coursetags",["core/ajax","core/templates"],(function(Ajax,Templates){
"use strict";
const SELECTORS={BOOST_UNION:'[data-region="course-content"][data-course-id]',STANDARD:'.coursebox[data-courseid]'};
const getTarget=el=>{const c=el.querySelector('.course-info-container');if(c)return{element:c,position:'beforeend'};const n=el.querySelector('.aalink.coursename');if(n)return{element:n,position:'afterend'};const s=el.querySelector('.content .summary');if(s)return{element:s,position:'afterend'};return{element:el,position:'beforeend'}};
let courseElements=new Map();
const activeTags=new Set(),courseTagMap=new Map(),tagIndex=new Map();
let allTagNames=[],extraPagesLoaded=false,extraPageLoadPromise=null;
const filterCourses=()=>{
courseElements.forEach((el,cid)=>{if(!activeTags.size){el.classList[el.dataset.extraPage?'add':'remove']('local-coursetags-hidden');return;}const t=courseTagMap.get(cid)??new Set();el.classList.toggle('local-coursetags-hidden',[...activeTags].every(k=>t.has(k))===false);});
document.body.classList.toggle('local-coursetags-filtering',activeTags.size>0);};
const rebuildTagNames=()=>{allTagNames.length=0;allTagNames.push(...[...tagIndex.entries()].sort((a,b)=>a[0].localeCompare(b[0])));};
const loadExtraPages=()=>{
if(extraPagesLoaded)return Promise.resolve();
if(extraPageLoadPromise)return extraPageLoadPromise;
const pageLinks=[...document.querySelectorAll('.pagination .page-item:not(.active) .page-link[href]')].filter(a=>/^\d+$/.test(a.textContent.trim())).map(a=>a.href);
if(!pageLinks.length){extraPagesLoaded=true;return Promise.resolve();}
const container=document.querySelector('.courses, [data-region="course-list-content"], .course-listing-content')??[...courseElements.values()][0]?.parentElement??null;
if(!container){extraPagesLoaded=true;return Promise.resolve();}
extraPageLoadPromise=(async()=>{
const newIds=[];
await Promise.all(pageLinks.map(async url=>{try{
const html=await(await fetch(url,{credentials:'same-origin'})).text();
const doc=new DOMParser().parseFromString(html,'text/html');
[...doc.querySelectorAll(SELECTORS.BOOST_UNION),...doc.querySelectorAll(SELECTORS.STANDARD)].forEach(el=>{
const id=parseInt(el.dataset.courseId||el.dataset.courseid,10);if(!id||courseElements.has(id))return;
const p=el.parentElement,useWrap=p&&(p.tagName==='LI'||p.className?.split(' ').some(c=>c.startsWith('col')));
const clone=(useWrap?p:el).cloneNode(true);
const courseEl=useWrap?(clone.querySelector(SELECTORS.BOOST_UNION)||clone.querySelector(SELECTORS.STANDARD)||clone):clone;
courseEl.classList.add('local-coursetags-hidden');courseEl.dataset.extraPage='true';
container.appendChild(clone);courseElements.set(id,courseEl);newIds.push(id);
});}catch(e){window.console?.warn('local_coursetags: failed to load extra page',url,e);}}));
if(newIds.length){try{
const res=await Ajax.call([{methodname:'local_coursetags_get_course_tags',args:{courseids:newIds}}])[0];
for(const d of res){if(!d.tags?.length)continue;const el=courseElements.get(d.courseid);if(!el)continue;
const ts=new Set();for(const t of d.tags){const k=t.rawname.toLowerCase();ts.add(k);if(!tagIndex.has(k))tagIndex.set(k,t.rawname);}
courseTagMap.set(d.courseid,ts);
try{const{html}=await Templates.renderForPromise('local_coursetags/coursetags',{tags:d.tags});const{element:tgt,position:p}=getTarget(el);tgt.insertAdjacentHTML(p,html);}catch(e){}}
rebuildTagNames();}catch(e){window.console?.warn('local_coursetags: extra page tag fetch error',e);}}
extraPagesLoaded=true;})();
return extraPageLoadPromise;};
const addActiveTag=(rawname,ac)=>{const key=rawname.toLowerCase();if(activeTags.has(key))return;activeTags.add(key);
const chip=document.createElement('span');chip.className='local-coursetags-filter-chip badge rounded-pill';chip.dataset.tagKey=key;chip.appendChild(document.createTextNode(rawname+' '));
const btn=document.createElement('button');btn.type='button';btn.className='local-coursetags-filter-remove';btn.setAttribute('aria-label','Remove filter: '+rawname);btn.textContent='×';
btn.addEventListener('click',()=>{activeTags.delete(key);chip.remove();filterCourses();ac.hidden=activeTags.size===0;});
chip.appendChild(btn);ac.appendChild(chip);ac.hidden=false;
loadExtraPages().then(()=>filterCourses());};
const init=async()=>{
document.querySelectorAll(SELECTORS.BOOST_UNION).forEach(el=>{const id=parseInt(el.dataset.courseId,10);if(id)courseElements.set(id,el)});
document.querySelectorAll(SELECTORS.STANDARD).forEach(el=>{const id=parseInt(el.dataset.courseid,10);if(id&&!courseElements.has(id))courseElements.set(id,el)});
if(!courseElements.size)return;
let results;try{results=await Ajax.call([{methodname:'local_coursetags_get_course_tags',args:{courseids:[...courseElements.keys()]}}])[0];}catch(e){window.console?.warn('local_coursetags: AJAX error',e);return}
for(const d of results){if(!d.tags?.length)continue;const ts=new Set();for(const t of d.tags){const k=t.rawname.toLowerCase();ts.add(k);if(!tagIndex.has(k))tagIndex.set(k,t.rawname);}courseTagMap.set(d.courseid,ts);}
rebuildTagNames();
for(const d of results){if(!d.tags?.length)continue;const el=courseElements.get(d.courseid);if(!el)continue;try{const{html}=await Templates.renderForPromise('local_coursetags/coursetags',{tags:d.tags});const{element:tgt,position:p}=getTarget(el);tgt.insertAdjacentHTML(p,html)}catch(e){window.console?.warn('local_coursetags: render error',d.courseid,e)}}
if(!tagIndex.size)return;
let inputWrap;try{const{html}=await Templates.renderForPromise('local_coursetags/filterbar',{});const wrap=document.createElement('div');wrap.innerHTML=html;inputWrap=wrap.firstElementChild;}catch(e){window.console?.warn('local_coursetags: filterbar render error',e);return}
const ac=document.createElement('div');ac.className='local-coursetags-active';ac.setAttribute('aria-live','polite');ac.hidden=true;
const actionBar=document.querySelector('#action_bar'),flexRow=actionBar?.querySelector('.d-flex');
if(flexRow){flexRow.appendChild(inputWrap);actionBar.appendChild(ac);}else{const fe=[...courseElements.values()][0];const fb=document.createElement('div');fb.className='local-coursetags-filterbar';fb.appendChild(inputWrap);fb.appendChild(ac);fe.parentElement.insertBefore(fb,fe);}
const input=inputWrap.querySelector('.local-coursetags-input'),suggestions=inputWrap.querySelector('.local-coursetags-suggestions');
let hi=-1;
const showSugg=matches=>{suggestions.innerHTML='';hi=-1;if(!matches.length){suggestions.hidden=true;return;}matches.forEach(([k,r])=>{const li=document.createElement('li');li.dataset.key=k;li.textContent=r;li.setAttribute('role','option');suggestions.appendChild(li);});suggestions.hidden=false;};
const selSugg=li=>{if(!li)return;const r=tagIndex.get(li.dataset.key);if(r)addActiveTag(r,ac);input.value='';suggestions.hidden=true;hi=-1;input.focus();};
input.addEventListener('focus',()=>{if(!input.value.trim())showSugg(allTagNames);});
input.addEventListener('input',()=>{const q=input.value.trim().toLowerCase();if(!q){showSugg(allTagNames);return;}showSugg(allTagNames.filter(([k])=>k.includes(q)).slice(0,8));});
input.addEventListener('keydown',e=>{const items=[...suggestions.querySelectorAll('li')];if(e.key==='ArrowDown'){e.preventDefault();hi=Math.min(hi+1,items.length-1);items.forEach((li,i)=>li.classList.toggle('active',i===hi));}else if(e.key==='ArrowUp'){e.preventDefault();hi=Math.max(hi-1,-1);items.forEach((li,i)=>li.classList.toggle('active',i===hi));}else if(e.key==='Enter'){e.preventDefault();selSugg(hi>=0?items[hi]:items[0]);}else if(e.key==='Escape'){suggestions.hidden=true;hi=-1;}});
input.addEventListener('blur',()=>{setTimeout(()=>{suggestions.hidden=true;hi=-1;},150);});
suggestions.addEventListener('mousedown',e=>{const li=e.target.closest('li');if(li){e.preventDefault();selSugg(li);}});
document.addEventListener('click',e=>{const badge=e.target.closest('.local-coursetags-badge');if(!badge)return;e.preventDefault();const r=badge.title||badge.textContent.trim();if(r)addActiveTag(r,ac);});
loadExtraPages();
};
return{init};
}));
